const token  = env.get('INFLUX_TOKEN');
const org    = env.get('INFLUX_ORG')    || 'santuario';
const bucket = env.get('INFLUX_BUCKET') || 'daly_bms';

const mppt_273   = flow.get('w_vrm_273')     || 0;
const mppt_289   = flow.get('w_vrm_289')     || 0;
const pvinverter = flow.get('w_vrm_32')      || 0;
const house_pw   = flow.get('house_power_w') || 0;

const mppt_only   = mppt_273 + mppt_289;
const solar_total = mppt_only + pvinverter;

global.set('mppt_power_w', mppt_only);
flow.set('solar_pw', solar_total);
node.status({ fill: 'green', shape: 'dot', text: `Sol: ${solar_total}W  Maison: ${house_pw}W` });

// — Output 1 : InfluxDB line protocol —
let influxMsg = null;
if (token) {
    const now = new Date();
    const parisISO = now.toLocaleString('sv-SE', { timeZone: 'Europe/Paris' });
    const day = parisISO.substring(0, 10);
    const ts  = Math.floor(Date.now() / 1000);
    const hostname = (env.get('HOSTNAME') || 'pi5').replace(/[^a-zA-Z0-9_-]/g, '_');
    const line = `solar_power,day=${day},host=${hostname} w_vrm_273=${mppt_273},w_vrm_289=${mppt_289},w_vrm_32=${pvinverter},solar_total=${solar_total},house_power=${house_pw} ${ts}`;
    influxMsg = {
        url:     `http://dalybms-influxdb:8086/api/v2/write?org=${org}&bucket=${bucket}&precision=s`,
        method:  'POST',
        payload: line,
        headers: {
            'Authorization': 'Token ' + token,
            'Content-Type':  'text/plain; charset=utf-8'
        }
    };
}

// — Output 2 : POST vers daly-bms-server —
const serverMsg = {
    url:     'http://192.168.1.141:8080/api/v1/solar/mppt-yield',
    method:  'POST',
    payload: JSON.stringify({ solar_total_w: solar_total, mppt_power_w: mppt_only, house_power_w: house_pw }),
    headers: { 'Content-Type': 'application/json' }
};

// — Données individuelles par MPPT (format v2) —
const mppts = [
    {
        Instance:   273,
        State:      flow.get('mppt_273_state')     || null,
        PvVoltage:  flow.get('mppt_273_pv_v')      !== undefined ? flow.get('mppt_273_pv_v')  : null,
        DcCurrent:  flow.get('mppt_273_dc_i')      !== undefined ? flow.get('mppt_273_dc_i')  : null,
        Power:      mppt_273,
        YieldToday: flow.get('mppt_273_yield_kwh') !== undefined ? flow.get('mppt_273_yield_kwh') : null
    },
    {
        Instance:   289,
        State:      flow.get('mppt_289_state')     || null,
        PvVoltage:  flow.get('mppt_289_pv_v')      !== undefined ? flow.get('mppt_289_pv_v')  : null,
        DcCurrent:  flow.get('mppt_289_dc_i')      !== undefined ? flow.get('mppt_289_dc_i')  : null,
        Power:      mppt_289,
        YieldToday: flow.get('mppt_289_yield_kwh') !== undefined ? flow.get('mppt_289_yield_kwh') : null
    }
];

// — Output 3 : MQTT pour santuario/meteo/venus (daly-bms-server l'écoute) —
const mqttMsg = {
    topic: 'santuario/meteo/venus',
    payload: JSON.stringify({
        Irradiance:     global.get('irradiance_wm2') || 0,
        TodaysYield:    Math.round((global.get('total_yield_today') || 0) * 10) / 10,
        YieldYesterday: global.get('yield_yesterday') || 0,
        WindSpeed:      global.get('outdoor_wind_speed') || 0,
        WindDirection:  global.get('outdoor_wind_dir') || 0,
        MpptPower:      mppt_only,
        SolarTotal:     solar_total,
        Mppts:          mppts
    }),
    retain: true
};

return [influxMsg, serverMsg, mqttMsg];

